import { NextRequest, NextResponse } from "next/server";
import fs from "fs/promises";
import path from "path";

export const runtime = "nodejs"; // important if you're using fs

export async function GET(
  req: NextRequest,
  { params }: { params: { jobId: string } }
) {
  const filePath = path.join(
    process.cwd(),
    "generated",              // your dir
    `${params.jobId}.docx`    // your naming scheme
  );

  try {
    const fileBuffer = await fs.readFile(filePath);

    // Convert Node Buffer -> Uint8Array (which is a valid BodyInit)
    const uint8 = new Uint8Array(fileBuffer);

    return new NextResponse(uint8, {
      status: 200,
      headers: {
        "Content-Type":
          "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        "Content-Disposition": `attachment; filename="generated-document-${params.jobId}.docx"`,
      },
    });
  } catch (err) {
    console.error("Error reading file", err);
    return new NextResponse("File not found", { status: 404 });
  }
}